async function main() {
  console.log("🌱 Seeding extra real ingredients...");
  const categories = await prisma.ingredientCategory.findMany();
  const categoryMap = Object.fromEntries(categories.map((c) => [c.slug, c.id]));

  let added = 0, skipped = 0;
  const seen = new Set<string>();
  for (const ing of EXTRA) {
    if (seen.has(ing.slug)) continue; // deduplicate within this file
    seen.add(ing.slug);
    const { categorySlug, ...data } = ing;
    const categoryId = categoryMap[categorySlug];
    if (!categoryId) { console.warn(`⚠ No category '${categorySlug}' for ${ing.name}`); skipped++; continue; }
    try {
      await prisma.ingredient.upsert({ where: { slug: data.slug }, update: { ...data, categoryId }, create: { ...data, categoryId } });
      added++;
    } catch (e) { console.warn(`⚠ Failed: ${ing.name}`, (e as Error).message); skipped++; }
  }
  console.log(`✅ ${added} added/updated, ${skipped} skipped`);
}

main().catch((e) => { console.error(e); process.exit(1); }).finally(() => prisma.$disconnect());
